import { Container, Row, Col, Card, Button, Badge } from "react-bootstrap";
import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import api from "../services/api";

function HomePage() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  const getStoredUser = () => {
    try {
      const rawUser = localStorage.getItem("user");
      if (!rawUser || rawUser === "undefined") return null;
      return JSON.parse(rawUser);
    } catch (error) {
      localStorage.removeItem("user");
      return null;
    }
  };

  const user = getStoredUser();

  const getBannerSrc = (bannerImage) => {
    if (!bannerImage) {
      return "https://via.placeholder.com/600x400?text=No+Image";
    }

    if (
      bannerImage.startsWith("http://") ||
      bannerImage.startsWith("https://")
    ) {
      return bannerImage;
    }

    return `/images/${bannerImage}`;
  };

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const response = await api.get("/events");

        const eventData = Array.isArray(response.data)
          ? response.data
          : Array.isArray(response.data?.data)
          ? response.data.data
          : [];

        setEvents(eventData);
      } catch (error) {
        console.error("Lỗi khi tải sự kiện:", error);
        setEvents([]);
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, []);

  return (
    <Container className="user-shell">
      <Row className="mb-5">
        <Col md={12}>
          <Card className="hero-card">
            <Card.Body className="p-4 p-lg-5">
              {user ? (
                <>
                  <div className="mb-3">
                    <span className="hero-chip">🎵 Concert hot</span>
                    <span className="hero-chip">🎫 Vé NFT minh bạch</span>
                    <span className="hero-chip">⚡ Thanh toán nhanh</span>
                  </div>

                  <div className="hero-title">
                    Chào mừng trở lại, {user.full_name}!
                  </div>

                  <div className="hero-text mb-4">
                    Khám phá những sự kiện nổi bật, mua vé nhanh chóng và quản lý
                    vé concert của bạn trên một giao diện hiện đại hơn.
                  </div>

                  <Button
                    className="soft-button soft-button-primary"
                    onClick={() => navigate("/profile")}
                  >
                    Xem hồ sơ & lịch sử mua vé
                  </Button>
                </>
              ) : (
                <>
                  <div className="mb-3">
                    <span className="hero-chip">🎶 Trải nghiệm concert mới</span>
                    <span className="hero-chip">🔐 Blockchain ticket</span>
                  </div>

                  <div className="hero-title">
                    Trải nghiệm mua vé concert hiện đại và minh bạch
                  </div>

                  <div className="hero-text mb-4">
                    Mua vé an toàn, theo dõi đơn hàng, và sở hữu NFT ticket cho các
                    sự kiện âm nhạc lớn nhất.
                  </div>

                  <Button
                    className="soft-button soft-button-primary"
                    onClick={() => navigate("/login")}
                  >
                    Tham gia ngay
                  </Button>
                </>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>

      <div className="section-title">Sự kiện nổi bật</div>
      <div className="section-subtitle">
        Những concert đang được quan tâm và mở bán trên nền tảng.
      </div>

      {loading ? (
        <div className="text-center p-5">Đang tải danh sách sự kiện...</div>
      ) : (
        <Row className="g-4">
          {events.length > 0 ? (
            events.map((event) => (
              <Col md={6} xl={4} key={event.id}>
                <Card className="event-card h-100">
                  <div className="event-card-image-wrap">
                    <Card.Img
                      variant="top"
                      src={getBannerSrc(event.banner_image)}
                      alt={event.title}
                      className="event-card-image"
                      onError={(e) => {
                        e.target.src =
                          "https://via.placeholder.com/600x400?text=No+Image";
                      }}
                    />
                  </div>

                  <Card.Body className="p-4 d-flex flex-column">
                    <div className="d-flex justify-content-between align-items-start mb-3">
                      <Badge bg="info" className="event-badge text-dark">
                        Music
                      </Badge>
                      <small className="text-muted fw-semibold">
                        {new Date(event.event_date).toLocaleDateString("vi-VN")}
                      </small>
                    </div>

                    <div className="event-title">{event.title}</div>

                    <div className="event-meta mb-3">{event.location}</div>

                    <Button
                      className="soft-button soft-button-primary mt-auto"
                      onClick={() => navigate(`/event/${event.id}`)}
                    >
                      Xem chi tiết & đặt vé
                    </Button>
                  </Card.Body>
                </Card>
              </Col>
            ))
          ) : (
            <Col md={12}>
              <Card className="user-card">
                <Card.Body className="p-5 text-center text-muted">
                  Hiện chưa có sự kiện nào được mở bán.
                </Card.Body>
              </Card>
            </Col>
          )}
        </Row>
      )}
    </Container>
  );
}

export default HomePage;
